{
  "intent": "check_and_fix",
  "intent_description": "Investigate why R2 Serial0/1/1 transitioned oper up -> lower-layer-down while admin up, and why R3 Serial0/1/1 was oper down/admin down; collect evidence to determine root cause and whether remediation (cable/clocking/config no shutdown) is required.",
  "target": "router2,router3",
  "needs_fix": true,
  "plan": {
    "problem": "Transient/lowered-layer/down state on R2 Serial0/1/1 while admin up, and R3 Serial0/1/1 oper/admin down; root cause unknown due to missing historical logs and config history; current running state conflicts with alert.",
    "fix_summary": "Collect interface logs, syslog, running-config snapshots, and config-change history for R2 and R3 around the event (±30–60 minutes). After evidence collection, determine whether to restore admin state on R3 or remediate physical/clocking issues on R2/R3.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "retrieve_interface_log",
        "target": "Serial0/1/1",
        "parameters": [
          "time_window=±30_minutes_from_event",
          "include_link_events",
          "include_clocking_errors",
          "include_line-protocol-messages"
        ]
      },
      {
        "id": 2,
        "device": "router3",
        "action": "retrieve_interface_log",
        "target": "Serial0/1/1",
        "parameters": [
          "time_window=±30_minutes_from_event",
          "include_link_events",
          "include_clocking_errors",
          "include_line-protocol-messages"
        ]
      },
      {
        "id": 3,
        "device": "router2",
        "action": "retrieve_running_config",
        "target": "Serial0/1/1",
        "parameters": [
          "include_interface_section",
          "snapshot_before_and_after_event_if_available"
        ]
      },
      {
        "id": 4,
        "device": "router3",
        "action": "retrieve_running_config",
        "target": "Serial0/1/1",
        "parameters": [
          "include_interface_section",
          "snapshot_before_and_after_event_if_available"
        ]
      },
      {
        "id": 5,
        "device": "router2",
        "action": "retrieve_config_change_history",
        "target": null,
        "parameters": [
          "time_window=±60_minutes_from_event",
          "include_audit_user_and_commit_ids"
        ]
      },
      {
        "id": 6,
        "device": "router3",
        "action": "retrieve_config_change_history",
        "target": null,
        "parameters": [
          "time_window=±60_minutes_from_event",
          "include_audit_user_and_commit_ids"
        ]
      },
      {
        "id": 7,
        "device": "router2",
        "action": "retrieve_syslog",
        "target": null,
        "parameters": [
          "time_window=±60_minutes_from_event",
          "include_boot_and_interface_messages"
        ]
      },
      {
        "id": 8,
        "device": "router3",
        "action": "retrieve_syslog",
        "target": null,
        "parameters": [
          "time_window=±60_minutes_from_event",
          "include_boot_and_interface_messages"
        ]
      }
    ]
  }
}

